class Solution {
    public int countLargestGroup(int n) {
        int[] counts = new int[100];
        for (int i = 1; i <= n; i++) {
            int sum = sumDigits(i);
            counts[sum]++;
        }
        int max = 0;
        for (int count : counts) {
            if (count > max) {
                max = count;
            }
        }
        int result = 0;
        for (int count : counts) {
            if (count == max) {
                result++;
            }
        }
        return result;
    }

    private int sumDigits(int num) {
        int sum = 0;
        while (num > 0) {
            sum += num % 10;
            num /= 10;
        }
        return sum;
    }
}

